/**
 * ESLint rule: jsx-props-per-line
 *
 * Проверяет, что JSX-пропсы, расположенные на отдельных строках, соответствуют правилам:
 * 1. Проп "key" всегда должен быть первым и отделяться пустой строкой от остальных пропсов.
 * 2. Spread-атрибуты ({...props}) должны идти сразу после key (или первыми при отсутствии key)
 *    и отделяться пустой строкой от обычных пропсов.
 * 3. Обычные пропсы могут быть разделены на группы пустыми строками.
 *    Внутри каждой группы пропсы должны быть отсортированы по длине строки (от коротких к длинным).
 *
 * Опции:
 * - ignoreDataAttributes: игнорировать data-* атрибуты при сортировке (по умолчанию false)
 * - ignoreAriaAttributes: игнорировать aria-* атрибуты при сортировке (по умолчанию false)
 */

export default {
  meta: {
    type: "layout",
    docs: {
      description: "Enforce props on new lines when line length exceeds maximum",
      category: "Stylistic Issues",
      recommended: false
    },
    fixable: "whitespace",
    schema: [
      {
        type: "object",
        properties: {
          ignoreDataAttributes: {
            type: "boolean",
            default: false
          },
          ignoreAriaAttributes: {
            type: "boolean",
            default: false
          }
        },
        additionalProperties: false
      }
    ]
  },

  create(context) {
    const options = context.options[0] || {};
    const ignoreDataAttributes = options.ignoreDataAttributes || false;
    const ignoreAriaAttributes = options.ignoreAriaAttributes || false;
    const sourceCode = context.getSourceCode();

    function getAttributeText(attribute) {
      return sourceCode.getText(attribute);
    }

    function getAttributeName(attribute) {
      if (attribute.type === "JSXAttribute") {
        return attribute.name.name;
      }
      return "";
    }

    function isSpreadAttribute(attribute) {
      return attribute.type === "JSXSpreadAttribute";
    }

    function shouldIgnoreAttribute(attributeName) {
      if (attributeName === "key") {
        return true;
      }
      if (ignoreDataAttributes && attributeName.startsWith("data-")) {
        return true;
      }
      if (ignoreAriaAttributes && attributeName.startsWith("aria-")) {
        return true;
      }
      return false;
    }

    function isKeyAttribute(attribute) {
      return getAttributeName(attribute) === "key";
    }

    function hasKeyAttribute(attributes) {
      return attributes.some(attr => isKeyAttribute(attr));
    }

    function arePropsOnSeparateLines(attributes) {
      if (attributes.length <= 1) return true;

      for (let i = 1; i < attributes.length; i++) {
        if (attributes[i].loc.start.line === attributes[i - 1].loc.start.line) {
          return false;
        }
      }
      return true;
    }

    /**
     * Проверяет, есть ли пустая строка между двумя атрибутами
     */
    function hasEmptyLineBetween(attr1, attr2) {
      return attr2.loc.start.line - attr1.loc.end.line >= 2;
    }

    /**
     * Разбивает атрибуты на группы по пустым строкам.
     * Spread-атрибуты и key не включаются в обычные группы
     */
    function splitIntoGroups(attributes) {
      const groups = [];
      let currentGroup = [];

      for (let i = 0; i < attributes.length; i++) {
        const attr = attributes[i];

        // key и spread обрабатываются отдельно — пропускаем
        if (isKeyAttribute(attr) || isSpreadAttribute(attr)) {
          continue;
        }

        // Проверяем пустую строку относительно последнего атрибута в текущей группе
        const lastInGroup = currentGroup[currentGroup.length - 1];
        if (lastInGroup && hasEmptyLineBetween(lastInGroup, attr)) {
          groups.push(currentGroup);
          currentGroup = [];
        }

        currentGroup.push(attr);
      }

      if (currentGroup.length > 0) {
        groups.push(currentGroup);
      }

      return groups;
    }

    /**
     * Проверяет, что key идёт первым и отделён пустой строкой
     */
    function checkKeyPosition(attributes) {
      if (!hasKeyAttribute(attributes)) return null;

      const keyIndex = attributes.findIndex(attr => isKeyAttribute(attr));

      if (keyIndex !== 0) {
        return "Prop 'key' should be first";
      }

      if (attributes.length > 1 && !hasEmptyLineBetween(attributes[0], attributes[1])) {
        return "Prop 'key' should be separated by empty line from other props";
      }

      return null;
    }

    /**
     * Проверяет, что spread-атрибуты идут сразу после key (или первыми) и отделены пустой строкой
     */
    function checkSpreadPosition(attributes) {
      const spreadIndices = [];
      const keyIndex = attributes.findIndex(attr => isKeyAttribute(attr));

      for (let i = 0; i < attributes.length; i++) {
        if (isSpreadAttribute(attributes[i])) {
          spreadIndices.push(i);
        }
      }

      if (spreadIndices.length === 0) return null;

      // Spread должны идти сразу после key (или с позиции 0)
      const expectedStart = keyIndex >= 0 ? keyIndex + 1 : 0;

      for (let j = 0; j < spreadIndices.length; j++) {
        if (spreadIndices[j] !== expectedStart + j) {
          return "Spread props should come first (after 'key' if present)";
        }
      }

      // После последнего spread должна быть пустая строка (если есть следующие атрибуты)
      const lastSpreadIndex = spreadIndices[spreadIndices.length - 1];
      if (lastSpreadIndex < attributes.length - 1) {
        const lastSpread = attributes[lastSpreadIndex];
        const nextAttr = attributes[lastSpreadIndex + 1];

        if (!hasEmptyLineBetween(lastSpread, nextAttr)) {
          return "Spread props should be separated by empty line from other props";
        }
      }

      return null;
    }

    /**
     * Проверяет, что внутри каждой группы пропсы отсортированы по длине
     */
    function checkGroupsOrdering(attributes) {
      const groups = splitIntoGroups(attributes);

      for (const group of groups) {
        const sortable = group.filter(attr => !shouldIgnoreAttribute(getAttributeName(attr)));

        for (let i = 1; i < sortable.length; i++) {
          const prevLength = getAttributeText(sortable[i - 1]).length;
          const currentLength = getAttributeText(sortable[i]).length;

          if (prevLength > currentLength) {
            return "Props should be ordered by line length (shortest to longest) within each group";
          }
        }
      }

      return null;
    }

    return {
      JSXElement(node) {
        const openingElement = node.openingElement;
        const attributes = openingElement.attributes;

        if (attributes.length <= 1) return;

        if (!arePropsOnSeparateLines(attributes)) {
          return;
        }

        const keyIssue = checkKeyPosition(attributes);
        const spreadIssue = checkSpreadPosition(attributes);
        const orderingIssue = checkGroupsOrdering(attributes);

        const issues = [keyIssue, spreadIssue, orderingIssue].filter(Boolean);

        if (issues.length === 0) return;

        context.report({
          node: openingElement,
          message: issues.join("; "),
          fix(fixer) {
            const attributeData = attributes.map(attr => ({
              node: attr,
              text: getAttributeText(attr),
              name: getAttributeName(attr),
              isKey: isKeyAttribute(attr),
              isSpread: isSpreadAttribute(attr),
              shouldIgnore: shouldIgnoreAttribute(getAttributeName(attr)) && !isKeyAttribute(attr)
            }));

            const keyAttr = attributeData.find(attr => attr.isKey);
            const spreadAttrs = attributeData.filter(attr => attr.isSpread);

            // Обычные атрибуты (не key, не spread) — разбиваем на существующие группы
            const regularAttrs = attributeData.filter(attr => !attr.isKey && !attr.isSpread);

            // Восстанавливаем группы из исходного порядка
            const groups = [];
            let currentGroup = [];

            for (let i = 0; i < regularAttrs.length; i++) {
              const attr = regularAttrs[i];
              const prevAttr = regularAttrs[i - 1];

              if (currentGroup.length > 0 && prevAttr && hasEmptyLineBetween(prevAttr.node, attr.node)) {
                groups.push(currentGroup);
                currentGroup = [];
              }

              currentGroup.push(attr);
            }
            if (currentGroup.length > 0) {
              groups.push(currentGroup);
            }

            // Сортируем внутри каждой группы по длине
            for (const group of groups) {
              const sortable = group.filter(a => !a.shouldIgnore);
              const ignored = group.filter(a => a.shouldIgnore);

              sortable.sort((a, b) => a.text.length - b.text.length);

              // Заменяем содержимое группы: сначала отсортированные, потом игнорируемые
              group.length = 0;
              group.push(...sortable, ...ignored);
            }

            // Собираем финальный порядок
            const baseIndent = " ".repeat(openingElement.loc.start.column);
            const propIndent = baseIndent + "  ";
            const parts = [];

            if (keyAttr) {
              parts.push(propIndent + keyAttr.text);
            }

            if (spreadAttrs.length > 0) {
              if (parts.length > 0) parts.push(""); // пустая строка после key
              for (const s of spreadAttrs) {
                parts.push(propIndent + s.text);
              }
            }

            for (const group of groups) {
              if (parts.length > 0) parts.push(""); // пустая строка перед группой
              for (const attr of group) {
                parts.push(propIndent + attr.text);
              }
            }

            const newText = parts.join("\n");

            const firstAttr = attributes[0];
            const lastAttr = attributes[attributes.length - 1];
            const start = firstAttr.range[0];
            const end = lastAttr.range[1];

            // Убираем лишние пробелы/переносы перед первым атрибутом
            const beforeFirst = sourceCode.getText().slice(openingElement.range[0], start);
            const lineBreakBeforeFirst = beforeFirst.includes("\n") ? "\n" : " ";

            return fixer.replaceTextRange([start, end], lineBreakBeforeFirst + newText + "\n" + baseIndent);
          }
        });
      }
    };
  }
};
